-- Deptex schema dump
-- Generated by backend/extraction-worker/scripts/dump-schema.ts
-- Single source of truth for local-mode extraction worker (PGLite backend).
-- Regenerate via `npm run schema:dump` whenever a migration lands in main.
--
-- RLS ENABLE statements are intentionally excluded — local mode runs without
-- auth and RLS-enabled tables without policies would return empty on SELECT.

-- ============================================
-- EXTENSIONS
-- ============================================
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE EXTENSION IF NOT EXISTS vector;


-- ============================================
-- ENUM TYPES
-- ============================================
CREATE TYPE public.asset_tier AS ENUM ('CROWN_JEWELS', 'EXTERNAL', 'INTERNAL', 'NON_PRODUCTION');

-- ============================================
-- TABLES
-- ============================================
