CREATE OR REPLACE FUNCTION public._pdv_reachability_rank(p_level text)
 RETURNS integer
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE lower(COALESCE(p_level, ''))
    WHEN 'confirmed' THEN 4
    WHEN 'data_flow' THEN 3
    WHEN 'function' THEN 2
    WHEN 'module' THEN 1
    ELSE 0
  END;
$function$
;

CREATE OR REPLACE FUNCTION public._pdv_severity_rank(p_severity text)
 RETURNS integer
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE lower(COALESCE(p_severity, ''))
    WHEN 'critical' THEN 4
    WHEN 'high' THEN 3
    WHEN 'medium' THEN 2
    WHEN 'low' THEN 1
    ELSE 0
  END;
$function$
;

CREATE OR REPLACE FUNCTION public.add_project_creator_as_owner()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  owner_role_id UUID;
  creator_id UUID;
BEGIN
  -- Get the owner role for this project
  SELECT id INTO owner_role_id FROM project_roles 
  WHERE project_id = NEW.id AND name = 'owner';
  
  -- Get the user who created the project (current authenticated user)
  creator_id := auth.uid();
  
  -- Add the creator as project owner if we have both IDs
  IF owner_role_id IS NOT NULL AND creator_id IS NOT NULL THEN
    INSERT INTO project_members (project_id, user_id, role_id)
    VALUES (NEW.id, creator_id, owner_role_id)
    ON CONFLICT (project_id, user_id) DO NOTHING;
  END IF;
  
  RETURN NEW;
END;
$function$
;

