CREATE OR REPLACE FUNCTION public.match_aegis_memories(query_embedding vector, match_threshold double precision, match_count integer, filter_org_id uuid, filter_category text DEFAULT NULL::text)
 RETURNS TABLE(id uuid, category text, key text, content text, similarity double precision)
 LANGUAGE sql
 STABLE
AS $function$
  SELECT id, category, key, content,
         1 - (embedding <=> query_embedding) AS similarity
  FROM aegis_memory
  WHERE organization_id = filter_org_id
    AND (filter_category IS NULL OR category = filter_category)
    AND (expires_at IS NULL OR expires_at > NOW())
    AND 1 - (embedding <=> query_embedding) > match_threshold
  ORDER BY embedding <=> query_embedding
  LIMIT match_count;
$function$
;

CREATE OR REPLACE FUNCTION public.pg_catalog_dump_v1()
 RETURNS TABLE(kind text, ord integer, ddl text)
 LANGUAGE sql
 SECURITY DEFINER
AS $function$
  SELECT 'enum'::text AS kind, 10 AS ord,
    'CREATE TYPE ' || n.nspname || '.' || t.typname || ' AS ENUM (' ||
    string_agg(quote_literal(e.enumlabel), ', ' ORDER BY e.enumsortorder) || ');' AS ddl
  FROM pg_type t
  JOIN pg_enum e ON e.enumtypid = t.oid
  JOIN pg_namespace n ON n.oid = t.typnamespace
  WHERE n.nspname = 'public'
  GROUP BY n.nspname, t.typname

  UNION ALL

  SELECT 'table'::text, 20,
    'CREATE TABLE IF NOT EXISTS public.' || quote_ident(c.table_name) || E' (\n' ||
    string_agg('  ' || quote_ident(c.column_name) || ' ' ||
      CASE
        WHEN c.data_type = 'USER-DEFINED' THEN c.udt_schema || '.' || c.udt_name
        WHEN c.data_type = 'ARRAY' THEN
          CASE WHEN c.udt_name LIKE E'\\_%' THEN substring(c.udt_name, 2) || '[]' ELSE c.udt_name END
        WHEN c.data_type = 'character varying' AND c.character_maximum_length IS NOT NULL
          THEN 'varchar(' || c.character_maximum_length || ')'
        WHEN c.data_type = 'numeric' AND c.numeric_precision IS NOT NULL
          THEN 'numeric(' || c.numeric_precision || COALESCE(',' || c.numeric_scale, '') || ')'
        ELSE c.data_type
      END ||
      CASE WHEN c.is_nullable = 'NO' THEN ' NOT NULL' ELSE '' END ||
      COALESCE(' DEFAULT ' || c.column_default, ''),
      E',\n' ORDER BY c.ordinal_position) || E'\n);' AS ddl
  FROM information_schema.columns c
  WHERE c.table_schema = 'public'
  GROUP BY c.table_name

  UNION ALL

  SELECT 'constraint'::text,
    30 + CASE con.contype WHEN 'p' THEN 0 WHEN 'u' THEN 1 WHEN 'c' THEN 2 WHEN 'f' THEN 3 ELSE 9 END,
    'ALTER TABLE public.' || quote_ident(con.conrelid::regclass::text) ||
    ' ADD CONSTRAINT ' || quote_ident(con.conname) || ' ' ||
    pg_get_constraintdef(con.oid) || ';'
  FROM pg_constraint con
  JOIN pg_namespace n ON n.oid = con.connamespace
  WHERE n.nspname = 'public'

  UNION ALL

  SELECT 'index'::text, 40, indexdef || ';'
  FROM pg_indexes
  WHERE schemaname = 'public'
    AND indexname NOT IN (
      SELECT conname FROM pg_constraint c2
      JOIN pg_namespace n2 ON n2.oid = c2.connamespace
      WHERE n2.nspname = 'public' AND c2.contype IN ('p', 'u')
    )

  UNION ALL

  SELECT 'function'::text, 50, pg_get_functiondef(p.oid) || ';'
  FROM pg_proc p
  JOIN pg_namespace n ON n.oid = p.pronamespace
  WHERE n.nspname = 'public' AND p.prokind = 'f'

  UNION ALL

  SELECT 'trigger'::text, 60, pg_get_triggerdef(t.oid) || ';'
  FROM pg_trigger t
  JOIN pg_class c ON c.oid = t.tgrelid
  JOIN pg_namespace n ON n.oid = c.relnamespace
  WHERE n.nspname = 'public' AND NOT t.tgisinternal;
$function$
;

CREATE OR REPLACE FUNCTION public.queue_fix_job(p_project_id uuid, p_organization_id uuid, p_fix_type text, p_strategy text, p_triggered_by uuid, p_osv_id text DEFAULT NULL::text, p_dependency_id uuid DEFAULT NULL::uuid, p_project_dependency_id uuid DEFAULT NULL::uuid, p_semgrep_finding_id uuid DEFAULT NULL::uuid, p_secret_finding_id uuid DEFAULT NULL::uuid, p_target_version text DEFAULT NULL::text, p_payload jsonb DEFAULT '{}'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_org_count INTEGER;
  v_job_id UUID;
BEGIN
  PERFORM 1 FROM organizations WHERE id = p_organization_id FOR UPDATE;

  SELECT COUNT(*) INTO v_org_count
  FROM project_security_fixes
  WHERE organization_id = p_organization_id
    AND status IN ('queued', 'running');

  IF v_org_count >= 5 THEN
    RAISE EXCEPTION 'MAX_CONCURRENT_FIXES: Organization has reached the maximum of 5 concurrent fix jobs';
  END IF;

  INSERT INTO project_security_fixes (
    project_id, organization_id, fix_type, strategy, triggered_by,
    osv_id, dependency_id, project_dependency_id,
    semgrep_finding_id, secret_finding_id, target_version, payload
  ) VALUES (
    p_project_id, p_organization_id, p_fix_type, p_strategy, p_triggered_by,
    p_osv_id, p_dependency_id, p_project_dependency_id,
    p_semgrep_finding_id, p_secret_finding_id, p_target_version, p_payload
  ) RETURNING id INTO v_job_id;

  RETURN v_job_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.reap_old_extractions(p_project_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_active TEXT;
  v_previous TEXT;
  v_pdv_deleted INTEGER := 0;
  v_semgrep_deleted INTEGER := 0;
  v_secret_deleted INTEGER := 0;
  v_flows_deleted INTEGER := 0;
  v_slices_deleted INTEGER := 0;
  v_files_deleted INTEGER := 0;
  v_fns_deleted INTEGER := 0;
  v_entry_points_deleted INTEGER := 0;
BEGIN
  SELECT active_extraction_run_id, previous_extraction_run_id
    INTO v_active, v_previous
  FROM projects WHERE id = p_project_id;

  IF v_active IS NULL THEN
    RETURN jsonb_build_object('skipped', true, 'reason', 'no_active_run');
  END IF;

  DELETE FROM project_dependency_vulnerabilities
  WHERE project_id = p_project_id
    AND extraction_run_id IS NOT NULL
    AND extraction_run_id <> v_active
    AND (v_previous IS NULL OR extraction_run_id <> v_previous);
  GET DIAGNOSTICS v_pdv_deleted = ROW_COUNT;

  DELETE FROM project_semgrep_findings
  WHERE project_id = p_project_id
    AND extraction_run_id IS NOT NULL
    AND extraction_run_id <> v_active
    AND (v_previous IS NULL OR extraction_run_id <> v_previous);
  GET DIAGNOSTICS v_semgrep_deleted = ROW_COUNT;

  DELETE FROM project_secret_findings
  WHERE project_id = p_project_id
    AND extraction_run_id IS NOT NULL
    AND extraction_run_id <> v_active
    AND (v_previous IS NULL OR extraction_run_id <> v_previous);
  GET DIAGNOSTICS v_secret_deleted = ROW_COUNT;

  DELETE FROM project_reachable_flows
  WHERE project_id = p_project_id
    AND extraction_run_id IS NOT NULL
    AND extraction_run_id <> v_active
    AND (v_previous IS NULL OR extraction_run_id <> v_previous);
  GET DIAGNOSTICS v_flows_deleted = ROW_COUNT;

  DELETE FROM project_usage_slices
  WHERE project_id = p_project_id
    AND extraction_run_id IS NOT NULL
    AND extraction_run_id <> v_active
    AND (v_previous IS NULL OR extraction_run_id <> v_previous);
  GET DIAGNOSTICS v_slices_deleted = ROW_COUNT;

  DELETE FROM project_dependency_files pdf
  USING project_dependencies pd
  WHERE pdf.project_dependency_id = pd.id
    AND pd.project_id = p_project_id
    AND pdf.extraction_run_id IS NOT NULL
    AND pdf.extraction_run_id <> v_active
    AND (v_previous IS NULL OR pdf.extraction_run_id <> v_previous);
  GET DIAGNOSTICS v_files_deleted = ROW_COUNT;

  DELETE FROM project_dependency_functions pdfn
  USING project_dependencies pd
  WHERE pdfn.project_dependency_id = pd.id
    AND pd.project_id = p_project_id
    AND pdfn.extraction_run_id IS NOT NULL
    AND pdfn.extraction_run_id <> v_active
    AND (v_previous IS NULL OR pdfn.extraction_run_id <> v_previous);
  GET DIAGNOSTICS v_fns_deleted = ROW_COUNT;

  DELETE FROM project_entry_points
  WHERE project_id = p_project_id
    AND extraction_run_id IS NOT NULL
    AND extraction_run_id <> v_active
    AND (v_previous IS NULL OR extraction_run_id <> v_previous);
  GET DIAGNOSTICS v_entry_points_deleted = ROW_COUNT;

  RETURN jsonb_build_object(
    'project_id', p_project_id,
    'active', v_active,
    'previous', v_previous,
    'pdv_deleted', v_pdv_deleted,
    'semgrep_deleted', v_semgrep_deleted,
    'secret_deleted', v_secret_deleted,
    'flows_deleted', v_flows_deleted,
    'slices_deleted', v_slices_deleted,
    'dep_files_deleted', v_files_deleted,
    'dep_functions_deleted', v_fns_deleted,
    'entry_points_deleted', v_entry_points_deleted
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.reap_orphaned_extractions(p_older_than_hours integer DEFAULT 24)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_orphan RECORD;
  v_cutoff TIMESTAMPTZ := NOW() - (p_older_than_hours || ' hours')::INTERVAL;
  v_runs_reaped INTEGER := 0;
  v_pdv_deleted INTEGER := 0;
  v_pd_deleted INTEGER := 0;
  v_semgrep_deleted INTEGER := 0;
  v_secret_deleted INTEGER := 0;
  v_flows_deleted INTEGER := 0;
  v_slices_deleted INTEGER := 0;
  v_files_deleted INTEGER := 0;
  v_fns_deleted INTEGER := 0;
  v_events_deleted INTEGER := 0;
  v_entry_points_deleted INTEGER := 0;
  v_temp INTEGER;
  v_orphan_runs JSONB := '[]'::JSONB;
BEGIN
  FOR v_orphan IN
    SELECT DISTINCT ej.project_id, ej.id::TEXT AS run_id
    FROM extraction_jobs ej
    JOIN projects p ON p.id = ej.project_id
    WHERE ej.status IN ('failed', 'cancelled')
      AND ej.created_at < v_cutoff
      AND ej.id::TEXT IS DISTINCT FROM COALESCE(p.active_extraction_run_id, '')
      AND ej.id::TEXT IS DISTINCT FROM COALESCE(p.previous_extraction_run_id, '')
      AND NOT EXISTS (
        SELECT 1 FROM extraction_jobs ej2
        WHERE ej2.project_id = ej.project_id
          AND ej2.status IN ('queued', 'processing')
      )
  LOOP
    DELETE FROM project_dependency_files
    WHERE extraction_run_id = v_orphan.run_id;
    GET DIAGNOSTICS v_temp = ROW_COUNT;
    v_files_deleted := v_files_deleted + v_temp;

    DELETE FROM project_dependency_functions
    WHERE extraction_run_id = v_orphan.run_id;
    GET DIAGNOSTICS v_temp = ROW_COUNT;
    v_fns_deleted := v_fns_deleted + v_temp;

    DELETE FROM project_dependency_vulnerabilities
    WHERE extraction_run_id = v_orphan.run_id;
    GET DIAGNOSTICS v_temp = ROW_COUNT;
    v_pdv_deleted := v_pdv_deleted + v_temp;

    DELETE FROM project_semgrep_findings
    WHERE extraction_run_id = v_orphan.run_id;
    GET DIAGNOSTICS v_temp = ROW_COUNT;
    v_semgrep_deleted := v_semgrep_deleted + v_temp;

    DELETE FROM project_secret_findings
    WHERE extraction_run_id = v_orphan.run_id;
    GET DIAGNOSTICS v_temp = ROW_COUNT;
    v_secret_deleted := v_secret_deleted + v_temp;

    DELETE FROM project_reachable_flows
    WHERE extraction_run_id = v_orphan.run_id;
    GET DIAGNOSTICS v_temp = ROW_COUNT;
    v_flows_deleted := v_flows_deleted + v_temp;

    DELETE FROM project_usage_slices
    WHERE extraction_run_id = v_orphan.run_id;
    GET DIAGNOSTICS v_temp = ROW_COUNT;
    v_slices_deleted := v_slices_deleted + v_temp;

    DELETE FROM project_vulnerability_events
    WHERE extraction_run_id = v_orphan.run_id;
    GET DIAGNOSTICS v_temp = ROW_COUNT;
    v_events_deleted := v_events_deleted + v_temp;

    DELETE FROM project_entry_points
    WHERE extraction_run_id = v_orphan.run_id;
    GET DIAGNOSTICS v_temp = ROW_COUNT;
    v_entry_points_deleted := v_entry_points_deleted + v_temp;

    DELETE FROM project_dependencies
    WHERE project_id = v_orphan.project_id
      AND last_seen_extraction_run_id = v_orphan.run_id;
    GET DIAGNOSTICS v_temp = ROW_COUNT;
    v_pd_deleted := v_pd_deleted + v_temp;

    v_orphan_runs := v_orphan_runs || jsonb_build_object(
      'project_id', v_orphan.project_id,
      'run_id', v_orphan.run_id
    );
    v_runs_reaped := v_runs_reaped + 1;
  END LOOP;

  RETURN jsonb_build_object(
    'cutoff_hours', p_older_than_hours,
    'runs_reaped', v_runs_reaped,
    'pdv_deleted', v_pdv_deleted,
    'pd_deleted', v_pd_deleted,
    'semgrep_deleted', v_semgrep_deleted,
    'secret_deleted', v_secret_deleted,
    'flows_deleted', v_flows_deleted,
    'slices_deleted', v_slices_deleted,
    'files_deleted', v_files_deleted,
    'fns_deleted', v_fns_deleted,
    'events_deleted', v_events_deleted,
    'entry_points_deleted', v_entry_points_deleted,
    'orphan_runs', v_orphan_runs
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.recover_stuck_extraction_jobs()
 RETURNS SETOF extraction_jobs
 LANGUAGE sql
AS $function$
  UPDATE extraction_jobs
  SET status = 'queued',
      machine_id = NULL,
      started_at = NULL,
      heartbeat_at = NULL,
      run_id = gen_random_uuid()
  WHERE status = 'processing'
    AND heartbeat_at < NOW() - INTERVAL '10 minutes'
    AND attempts < max_attempts
  RETURNING *;
$function$
;

CREATE OR REPLACE FUNCTION public.recover_stuck_fix_jobs()
 RETURNS SETOF project_security_fixes
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN QUERY
  UPDATE project_security_fixes
  SET status = 'queued',
      machine_id = NULL,
      heartbeat_at = NULL,
      run_id = gen_random_uuid()
  WHERE status = 'running'
    AND heartbeat_at < NOW() - INTERVAL '5 minutes'
    AND attempts < max_attempts
  RETURNING *;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.recover_stuck_watchtower_jobs()
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  recovered INTEGER;
BEGIN
  UPDATE watchtower_jobs
  SET status = 'queued',
      machine_id = NULL,
      started_at = NULL,
      heartbeat_at = NULL,
      updated_at = NOW()
  WHERE status = 'processing'
    AND heartbeat_at < NOW() - INTERVAL '5 minutes'
    AND attempt < max_attempts;
  GET DIAGNOSTICS recovered = ROW_COUNT;

  UPDATE watchtower_jobs
  SET status = 'failed',
      error_message = 'Exhausted max attempts',
      completed_at = NOW(),
      updated_at = NOW()
  WHERE status = 'processing'
    AND heartbeat_at < NOW() - INTERVAL '5 minutes'
    AND attempt >= max_attempts;

  RETURN recovered;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.resume_sla_shift_deadlines(p_organization_id uuid, p_pause_duration_seconds integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_count INTEGER;
BEGIN
  UPDATE project_dependency_vulnerabilities pdv
  SET
    sla_deadline_at = pdv.sla_deadline_at + (p_pause_duration_seconds || ' seconds')::INTERVAL,
    sla_warning_at = pdv.sla_warning_at + (p_pause_duration_seconds || ' seconds')::INTERVAL
  WHERE pdv.project_id IN (SELECT id FROM projects WHERE organization_id = p_organization_id)
    AND pdv.sla_status IN ('on_track', 'warning')
    AND pdv.sla_deadline_at IS NOT NULL;

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$function$
;

